// Added by Codex: project documentation comment for node_modules\tailwindcss\src\postcss-plugins\nesting\index.js
import { nesting } from './plugin'

export default Object.assign(
  function (opts) {
    return {
      postcssPlugin: 'tailwindcss/nesting',
      Once(root, { result }) {
        return nesting(opts)(root, result)
      },
    }
  },
  { postcss: true }
)

